import os
from flask import Flask, request, make_response
from datetime import datetime, timedelta
import pickle
import json

app = Flask(__name__)

# Set up cache directory and file suffix
cache_dir = 'cache'
file_suffix = '.pkl'

def _get_cache_filename(url):
    return os.path.join(cache_dir, f'{url}{file_suffix}')

def _save_to_disk(filename, data):
    with open(filename, 'wb') as f:
        pickle.dump(data, f)

def _load_from_disk(filename):
    try:
        with open(filename, 'rb') as f:
            return pickle.load(f)
    except Exception as e:
        print(f'Error loading cache: {e}')
        return None

def is_cache_valid(filename, expires_in):
    cache_timestamp = os.path.getmtime(filename)
    if datetime.now() - timedelta(seconds=expires_in) > datetime.fromtimestamp(cache_timestamp):
        return False
    return True

@app.route('/expensive_api', methods=['GET'])
def expensive_api():
    url = request.args['url']
    
    # Check if cache exists and is valid
    filename = _get_cache_filename(url)
    if os.path.exists(filename) and is_cache_valid(filename, 300):  # Cache expires after 5 minutes
        return make_response(json.dumps(_load_from_disk(filename)), mimetype='application/json')
    
    # Fetch data from API (this will be an expensive operation)
    api_data = {'data': 'some_api_response'}
    
    # Save to disk for future requests
    _save_to_disk(filename, api_data)
    
    return make_response(json.dumps(api_data), mimetype='application/json')

if __name__ == '__main__':
    if not os.path.exists(cache_dir):
        os.makedirs(cache_dir)
    app.run(debug=True)